 {"id":"bd-128s","title":"Add budget-aware rendering to all harness widgets","description":"# Add budget-aware rendering to all harness widgets

## Background
Part of Render Budget Enforcement (bd-1iqn). All harness-essential widgets must respect the RenderBudget and degrade gracefully.

## Widget Changes Required

### Panel Widget
```rust
impl Widget for Panel {
    fn render(&self, area: Rect, buf: &mut Buffer, budget: &RenderBudget) {
        match budget.degradation() {
            DegradationLevel::Full => {
                self.render_unicode_border(area, buf);
                self.render_title_styled(area, buf);
                self.render_shadow(area, buf);
            }
            DegradationLevel::SimpleBorders => {
                self.render_ascii_border(area, buf);  // +- instead of ╭─
                self.render_title_styled(area, buf);
                // Skip shadow
            }
            DegradationLevel::NoStyling => {
                self.render_ascii_border(area, buf);
                self.render_title_plain(area, buf);
            }
            DegradationLevel::EssentialOnly => {
                // Skip border entirely, just mark area
                self.render_content_only(area, buf);
            }
            DegradationLevel::Skeleton => {
                // Just fill with placeholder
                buf.fill_rect(area, Cell::new(' '));
            }
            DegradationLevel::SkipFrame => {
                // Do nothing
            }
        }
    }
}
```

### Viewport/LogViewer Widget
```rust
impl Widget for Viewport {
    fn render(&self, area: Rect, buf: &mut Buffer, budget: &RenderBudget) {
        // Always render visible content (essential)
        let visible_lines = self.visible_range(area.height);

        for (idx, line) in visible_lines.enumerate() {
            if budget.degradation().apply_styling() {
                line.render_styled(area.x, area.y + idx as u16, buf);
            } else {
                line.render_plain(area.x, area.y + idx as u16, buf);
            }
        }

        // Scrollbar is decorative
        if budget.degradation().render_decorative() {
            self.render_scrollbar(area, buf);
        }
    }
}
```

### TextInput Widget
```rust
impl Widget for TextInput {
    fn render(&self, area: Rect, buf: &mut Buffer, budget: &RenderBudget) {
        // Input is always essential
        let text_style = if budget.degradation().apply_styling() {
            self.style
        } else {
            Style::default()
        };

        buf.set_string(area.x, area.y, &self.value, text_style);

        // Cursor is essential
        let cursor_x = area.x + self.cursor_pos as u16;
        buf.set_cell(cursor_x, area.y, Cell::new('_').style(text_style));
    }
}
```

### Progress Widget
```rust
impl Widget for Progress {
    fn render(&self, area: Rect, buf: &mut Buffer, budget: &RenderBudget) {
        match budget.degradation() {
            DegradationLevel::Full | DegradationLevel::SimpleBorders => {
                // Full Unicode progress bar with gradient
                self.render_gradient_bar(area, buf);
            }
            DegradationLevel::NoStyling => {
                // ASCII progress bar without colors
                self.render_ascii_bar(area, buf);
            }
            _ => {
                // Just show percentage text
                let pct = format\!("{}%", (self.ratio * 100.0) as u8);
                buf.set_string(area.x, area.y, &pct, Style::default());
            }
        }
    }
}
```

## Widget Trait Update

```rust
/// Widget trait with optional budget parameter
pub trait Widget {
    /// Render with budget awareness
    fn render(&self, area: Rect, buf: &mut Buffer, budget: &RenderBudget);

    /// Mark widget as essential (never skipped in EssentialOnly)
    fn is_essential(&self) -> bool { false }
}
```

